// Verify uniqueness
const names = ingredients.map(i => i.name);
const dupes = names.filter((n, i) => names.indexOf(n) !== i);
if (dupes.length > 0) {
  console.error('Duplicate names found:', dupes);
  process.exit(1);
}

console.log(`Generated ${ingredients.length} ingredients`);
console.log(`Categories: ${Object.entries(
  ingredients.reduce((acc, i) => { acc[i.category] = (acc[i.category] || 0) + 1; return acc; }, {})
).map(([k,v]) => `${k}:${v}`).join(', ')}`);
console.log(`Pantry staples: ${ingredients.filter(i => i.isPantryStaple).length}`);
console.log(`With Finnish aliases: ${ingredients.filter(i => i.aliases.length > 0).length}`);

writeFileSync(join(__dirname, 'ingredients.json'), JSON.stringify(ingredients, null, 2) + '\n');
console.log('Written to packages/db/data/ingredients.json');
